AddWaterBuff = class("AddWaterBuff", BaseBuff)

function AddWaterBuff:doAction()
    local player = PlayerManager:getPlayerByUserId(self.targetUid)
    if not player then
        return
    end
    if not player.isLife then
        self:onRemove()
        return
    end
    player:addWaterLevel(self.value)
end

return AddWaterBuff